{
  "core_question": "How should a US-based clinical-stage biotech structure and value a co-development/co-commercialization deal with an EU-based pharma, balancing clinical, regulatory, IP, legal, and financial risks and rewards?",
  "rationale": "The question spans clinical program risk assessment (healthcare), jurisdictional rights and regulatory pathways (legal), and valuation/financial structuring (finance).",
  "routes": ["healthcare", "legal", "finance"],
  "sub_questions": {
    "healthcare": "Given a single Phase 3 oncology asset with potential FDA accelerated approval, what are the key clinical program risks, milestones for milestone payment calibration, and IP considerations that should be factored into the valuation model?",
    "legal": "What legal issues arise from assigning US territorial rights to the biotech and EU/UK rights to the pharma, including regulatory approvals, IP protection across jurisdictions, and contract provisions needed to manage accelerated approval pathways and royalty tiers?",
    "finance": "How can we construct an rNPV-based valuation model that incorporates upfront payments, milestone milestones, tiered royalties, and territorial splits, and what sensitivity analyses should be performed to assess deal economics?"
  },
  "requires_recency_disclosure": true,
  "recency_notes": "Potentially stale FDA accelerated approval guidance, EU/UK regulatory changes post-Brexit, recent IP law updates, and current market conditions for oncology assets."
}
